head.script:
/**
 * 화 면 명 : 감가상각비추정
 * 메뉴경로 : 회계/재무회계/고정자산/
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ac/fi/fixedaset/fi_302_01_05b.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2025-11-24
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항 : 
 *    1. (2026-03-27, 기준)피벗으로 작업했다가 속도/디자인/엑셀 이슈로 인해 일반 그리드로 작업
 * 수정이력 :
 *    - 2025-11-24      배기원    최초작성
 */
//hidden 값
scwin.txtCoClsCd = "";  //회사구분코드(hidden, 회사팝업호출 시)

//로그인 정보
scwin.memJson;
scwin.vLoginCoCd;       //소속자회사
scwin.vLoginCoClsCd;    //회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd;   //사용자소속구분코드
scwin.isSubCompany;
scwin.privAdmin;

scwin.initJson = {};    //초기세팅값(TOBE)
scwin.first  = 0;
scwin.search = "";

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    // scwin.f_setHeader();
    // scwin.f_setDefault();
    // scwin.f_QryCond();
    // scwin.f_setCompanyInfo();
    // $c.gus.cfDisableObjects([ed_searchFixedAsetNo]);

    scwin.memJson = $c.data.getMemInfo();
    scwin.vLoginCoCd     = $c.gus.cfIsNull(scwin.memJson["coCd"]) ? "" : scwin.memJson["coCd"];                     //소속자회사
    scwin.vLoginCoClsCd  = $c.gus.cfIsNull(scwin.memJson["coClsCd"]) ? "" : scwin.memJson["coClsCd"];               //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson["userHomeClsCd"]) ? "" : scwin.memJson["userHomeClsCd"];   //사용자소속구분코드
    scwin.isSubCompany   = false;
    scwin.privAdmin      = $c.gus.cfIsNull(scwin.memJson["privAdmin"]) ? "" : scwin.memJson["privAdmin"];           //관리자권한
    scwin.first = 0;

};

/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    ds_masterResult.removeAll();
    dma_lastCalculationDate.setEmptyValue();
    scwin.search = "";

    gr_masterResult1.hide();
    gr_masterResult2.show("");
    gr_masterResult3.hide();
    gr_masterResult1.setNoResultMessageVisible(false);
    gr_masterResult2.setNoResultMessageVisible(false);
    gr_masterResult3.setNoResultMessageVisible(false);
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function() {
    const codeOptions = [
          { grpCd: "FI028", compID: "lc_acqCls" }        //자산취득구분
    ];
    $c.data.setCommonCode(codeOptions);


    scwin.f_setDefault();
    //scwin.f_QryCond();
    scwin.f_setCompanyInfo();
    scwin.setInit();
    $c.gus.cfDisableObjects([ed_searchFixedAsetNo]);
};

/**
 * $c.data.setCommonCode 함수의 콜백함수
 */
scwin.callBackCommonCode = function() {
    scwin.initJson = dma_search.getJSON();
};

/**
 * 조회필드 CLEAR
 */
scwin.f_FieldClear = function() {
    $c.gus.cfInitObjects(tbl_search, [ed_coCd, ed_coNm]);
    //dma_search.setJSON(scwin.initJson);
    scwin.f_setDefault();
    ed_coCd.hidVal = "";         //회사코드(조회)
};

/**
 * 자회사 회계 시스템 추가에 따른 설정 
 */
scwin.f_setCompanyInfo = function() {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를 '동부 EXPRESS'로 Default set
    if (scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD) {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
    }
    ed_coCd.setValue(scwin.vLoginCoCd);
    scwin.f_PopUpCompanyInfo('T');
};


/**
 * 회사코드 팝업호출(UDC)
 */
scwin.f_PopUpCompanyInfo = function (pWinCloseTF) {
    //asis 소스
    // var rtnList = cfCommonPopUp("retrieveDongbuGroupCompanyInfo"
    //     , ed_coCd.getValue(), ed_coNm.value
    //     , pWinCloseTF, null, null, null, null
    //     , null, null, null, null, null);
    // // SET
    // if (rtnList != null) {
    //     if (rtnList[0] == "N/A") return;

    //     ed_coCd.setValue = rtnList[0]; // 코드
    //     ed_coNm.value = rtnList[5]; // 회사명
    //     ed_coCd.hidVal = rtnList[0]; // 히든값
    //     scwin.txtCoClsCd = rtnList[1]; // 회사구분
    //     $c.gus.cfInitObjects([ed_srchAcctDeptCd, ed_srchAcctDeptNm]); // 조회조건 - 귀속부서 From
    // } else {
    //     ed_coCd.setValue = "";
    //     ed_coNm.value = "";
    //     ed_coCd.hidVal = "";
    //     scwin.txtCoClsCd = "";
    // }

    // if (scwin.txtCoClsCd > 'scwin.ACConstants.CO_CLS_CD_DONGBU') { // 자회사 회계 시스템
    //     scwin.isSubCompany = true;
    // } else {
    //     scwin.isSubCompany = false;
